static void cmd_dump_memory(uint32_t address, uint32_t length) {
    if (length == 0) {
        uart_puts("Error: Length must be greater than 0.\r\n");
        return;
    }
    char line_buf[80]; // Enough for address + 16 bytes (hex) + ASCII + spaces + \0
    char hex_byte[3];
    char hex_addr[9];

    uart_puts("Dumping memory from 0x");
    uint32_to_hex(address, hex_addr);
    uart_puts(hex_addr);
    uart_puts(" (Length: ");
    uint32_to_dec(length, hex_addr); // Re-use hex_addr buffer for decimal
    uart_puts(hex_addr);
    uart_puts(" bytes):\r\n");

    for (uint32_t i = 0; i < length; i += 16) {
        uint32_t current_addr = address + i;
        uint32_to_hex(current_addr, hex_addr);
        strcpy(line_buf, hex_addr);
        strcat(line_buf, ": ");
        char ascii_buf[17];
        ascii_buf[16] = '\0';

        for (uint32_t j = 0; j < 16; j++) {
            if (i + j < length) {
                uint8_t byte = *(volatile uint8_t *)(current_addr + j);
                hex_byte[0] = "0123456789ABCDEF"[(byte >> 4) & 0xF];
                hex_byte[1] = "0123456789ABCDEF"[byte & 0xF];
                hex_byte[2] = '\0';
                strcat(line_buf, hex_byte);
                strcat(line_buf, " ");
                ascii_buf[j] = (byte >= 0x20 && byte <= 0x7E) ? byte : '.';
            } else {
                strcat(line_buf, "   ");
                ascii_buf[j] = ' ';
            }
        }
        strcat(line_buf, " |");
        strcat(line_buf, ascii_buf);
        strcat(line_buf, "|\r\n");
        uart_puts(line_buf);
    }
}

static void cmd_read_flash(uint32_t address, uint32_t length) {
    if (address < FLASH_START_ADDRESS || (address + length) > FLASH_END_ADDRESS) {
        uart_puts("Error: Address out of flash bounds.\r\n");
        return;
    }
    cmd_dump_memory(address, length); // Flash read is similar to memory dump
}

