void debug_shell_process(void) {
    char c;
    if (uart_getc_nb(&c) == 0) { // Character received
        uart_putc(c); // Echo character back

        if (c == '\r' || c == '\n') {
            cmd_buffer[cmd_buffer_idx] = '\0'; // Null-terminate the command
            uart_puts("\r\n"); // Newline after command entry

            if (cmd_buffer_idx > 0) {
                // Process command
                char *token;
                char *args[3]; // Max 3 arguments (command, addr, len)
                int arg_count = 0;

                // Create a mutable copy of cmd_buffer for strtok
                char cmd_buffer_copy[CMD_BUFFER_SIZE];
                strncpy(cmd_buffer_copy, cmd_buffer, CMD_BUFFER_SIZE);
                cmd_buffer_copy[CMD_BUFFER_SIZE - 1] = '\0'; // Ensure null-termination

                token = strtok(cmd_buffer_copy, " ");
                while (token != NULL && arg_count < 3) {
                    args[arg_count++] = token;
                    token = strtok(NULL, " ");
                }

                if (arg_count > 0) {
                    if (strcmp(args[0], "dump_memory") == 0) {
                        if (arg_count == 3) {
                            uint32_t addr = hex_to_uint32(args[1]);
                            uint32_t len = hex_to_uint32(args[2]);
                            cmd_dump_memory(addr, len);
                        } else {
                            uart_puts("Usage: dump_memory <address_hex> <length_hex>\r\n");
                        }
                    } else if (strcmp(args[0], "read_flash") == 0) {
                        if (arg_count == 3) {
                            uint32_t addr = hex_to_uint32(args[1]);
                            uint32_t len = hex_to_uint32(args[2]);
                            cmd_read_flash(addr, len);
                        } else {
                            uart_puts("Usage: read_flash <address_hex> <length_hex>\r\n");
                        }
                    } else if (strcmp(args[0], "get_config") == 0) {
                        if (arg_count == 1) {
                            cmd_get_config();
                        } else {
                            uart_puts("Usage: get_config\r\n");
                        }
                    } else if (strcmp(args[0], "help") == 0) {
                        uart_puts("Available commands:\r\n");
                        uart_puts("  dump_memory <address_hex> <length_hex>\r\n");
                        uart_puts("  read_flash <address_hex> <length_hex>\r\n");
                        uart_puts("  get_config\r\n");
                        uart_puts("  help\r\n");
                    } else {
                        uart_puts("Unknown command. Type 'help' for a list of commands.\r\n");
                    }
                }
            }
            cmd_buffer_idx = 0; // Reset buffer index
            print_prompt();     // Show new prompt
        } else if (c == 0x7F || c == 0x08) { // Backspace
            if (cmd_buffer_idx > 0) {
                cmd_buffer_idx--;
                uart_putc(' '); // Erase character on console
                uart_putc(0x7F); // Move cursor back (for most terminals)
            }
        } else if (c >= 0x20 && c <= 0x7E) { // Printable character
            if (cmd_buffer_idx < CMD_BUFFER_SIZE - 1) {
                cmd_buffer[cmd_buffer_idx++] = c;
            }
        }
    }
}
